mapper.insert:
INSERT INTO camera_results (
    record_id, camera_code, camera_name, status, quality_score,
    screenshot_path, error_message, sync_version
) VALUES (
    #{recordId}, #{cameraCode}, #{cameraName}, #{status}, #{qualityScore},
    #{screenshotPath}, #{errorMessage}, #{syncVersion}
)

mapper.select:
SELECT *
FROM camera_results
WHERE sync_version > #{syncVersion}
ORDER BY sync_version ASC
LIMIT #{limit}
